import React, { useState, useEffect } from "react";
import axios from "axios";

const SendEmailPage = () => {
  const [subject, setSubject] = useState("");
  const [group, setGroup] = useState("all");
  const [template, setTemplate] = useState("promo");
  const [html, setHtml] = useState("");
  const [status, setStatus] = useState("");
  const [loading, setLoading] = useState(false);

  // Mẫu email
  const templates = {
    promo: `<h2>🎉 Ưu đãi đặc biệt!</h2><p>Giảm 20% tất cả sản phẩm tuần này!</p>`,
    welcome: `<h2>🌸 Chào mừng đến với shop!</h2><p>Cảm ơn bạn đã đồng hành!</p>`,
  };

  // Tự động load preview khi chọn template
  useEffect(() => {
    setHtml(templates[template]);
  }, [template]);

  const handleSend = async () => {
    if (!subject) {
      setStatus("❌ Thiếu tiêu đề email");
      return;
    }

    setLoading(true);
    setStatus("");

    try {
      const res = await axios.post("http://localhost:5000/api/email/send", {
        subject,
        group,
        template: html,
        html,
        templateName: template
      });

      if (res.data.success) {
        setStatus("✔ Gửi email thành công!");
      } else {
        setStatus("❌ Gửi email thất bại!");
      }
    } catch (err) {
      console.error(err);
      setStatus("❌ Không thể gửi email (frontend error)");
    }

    setLoading(false);
  };

  return (
    <div style={{ padding: "30px" }}>
      <h1>📧 Gửi Email Marketing</h1>

      <div className="card">
        <label>Tiêu đề Email</label>
        <input
          className="input"
          value={subject}
          onChange={(e) => setSubject(e.target.value)}
          placeholder="Nhập tiêu đề..."
        />

        <label>Gửi đến nhóm</label>
        <select className="input" value={group} onChange={(e) => setGroup(e.target.value)}>
          <option value="all">👥 Tất cả khách hàng</option>
          <option value="user">👤 Người dùng</option>
          <option value="admin">⭐ Admin</option>
          <option value="newsletter">📰 Newsletter</option>
          <option value="vip">👑 VIP</option>
        </select>

        <label>Mẫu email</label>
        <select className="input" value={template} onChange={(e) => setTemplate(e.target.value)}>
          <option value="promo">🎁 Khuyến mãi</option>
          <option value="welcome">🌸 Chào mừng</option>
        </select>

        <button className="btn" onClick={handleSend} disabled={loading}>
          {loading ? "Đang gửi..." : "📨 Gửi Email"}
        </button>

        {status && <p className="status">{status}</p>}
      </div>

      <h2>🔍 Preview</h2>
      <div className="preview" dangerouslySetInnerHTML={{ __html: html }} />
    </div>
  );
};

export default SendEmailPage;
